def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about airports (or related entities) into a single
    fluent, complex sentence. Unknown predicates fall back to a generic phrasing.
    """
    if not triples:
        return ""

    def _clean(val: str) -> str:
        """Remove surrounding quotes if present."""
        return val.strip('"').strip("'")

    # Helper to build a clause for a single triple
    def _clause(s: str, p: str, o: str, first: bool = False) -> str:
        # Primary airport‑specific predicates
        if p == "cityServed":
            return f"{s} serves the city of {o}" if first else f"which serves the city of {o}"
        if p == "location":
            return f"{s} is located in {o}" if first else f"located in {o}"
        if p == "country":
            return f"{s} is in {o}" if first else f"which is in {o}"
        if p == "isPartOf":
            return f"{s} is part of {o}" if first else f"part of {o}"
        if p == "elevationAboveTheSeaLevel":
            return f"{s} lies at an elevation of {o} metres above sea level" if first else f"at an elevation of {o} metres above sea level"
        if p == "elevationAboveTheSeaLevelInFeet":
            return f"{s} lies at an elevation of {o} feet above sea level" if first else f"at an elevation of {o} feet above sea level"
        if p == "elevationAboveTheSeaLevelInMetres":
            return f"{s} lies at an elevation of {o} metres above sea level" if first else f"at an elevation of {o} metres above sea level"
        if p == "operatingOrganisation":
            return f"{s} is operated by {o}" if first else f"operated by {o}"
        if p == "runwaySurfaceType":
            return f"{s} has a runway surface of {o}" if first else f"with a runway surface of {o}"
        if p == "runwayName":
            return f"{s}'s runway is named {o}" if first else f"runway named {o}"
        if p == "runwayLength":
            return f"{s}'s runway length is {o}" if first else f"runway length of {o}"
        # Runway length variants
        if p.endswith("RunwayLengthFeet"):
            idx = p.split("Runway")[0]
            return f"{s}'s {idx.lower()} runway is {o} feet long" if first else f"{idx.lower()} runway is {o} feet long"
        if p.endswith("RunwayLengthMetre"):
            idx = p.split("Runway")[0]
            return f"{s}'s {idx.lower()} runway is {o} metres long" if first else f"{idx.lower()} runway is {o} metres long"
        # Runway surface type variants
        if p.endswith("RunwaySurfaceType"):
            idx = p.split("Runway")[0]
            return f"{s}'s {idx.lower()} runway surface is {o}" if first else f"{idx.lower()} runway surface is {o}"
        # Runway number variants
        if p.endswith("RunwayNumber"):
            idx = p.split("Runway")[0]
            return f"{s}'s {idx.lower()} runway number is {o}" if first else f"{idx.lower()} runway number is {o}"
        # Aviation codes
        if p == "iataLocationIdentifier":
            return f"{s} has IATA code {o}" if first else f"IATA code {o}"
        if p == "icaoLocationIdentifier":
            return f"{s} has ICAO code {o}" if first else f"ICAO code {o}"
        if p == "locationIdentifier":
            return f"{s} has location identifier {o}" if first else f"location identifier {o}"
        # Ownership and administration
        if p == "owner":
            return f"{s} is owned by {o}" if first else f"owned by {o}"
        if p == "largestCity":
            return f"The largest city of {s} is {o}" if first else f"largest city is {o}"
        if p == "capital":
            return f"The capital of {s} is {o}" if first else f"capital is {o}"
        if p == "language" or p == "officialLanguage":
            return f"The official language of {s} is {o}" if first else f"official language is {o}"
        if p == "leader":
            return f"The leader of {s} is {o}" if first else f"leader is {o}"
        if p == "leaderTitle":
            return f"The leader title of {s} is {o}" if first else f"leader title is {o}"
        if p == "leaderParty":
            return f"The leader of {s} belongs to the {o} party" if first else f"leader belongs to the {o} party"
        if p == "mayor":
            return f"The mayor of {s} is {o}" if first else f"mayor is {o}"
        if p == "nativeName":
            return f"{s}'s native name is {o}" if first else f"native name is {o}"
        if p == "administrativeArrondissement":
            return f"{s} is in the {o}" if first else f"administrative arrondissement is {o}"
        if p == "currency":
            return f"{s} uses the {o}" if first else f"currency is {o}"
        if p == "demonym":
            return f"People from {s} are called {o}" if first else f"demonym is {o}"
        if p == "areaCode":
            return f"{s}'s area code is {o}" if first else f"area code is {o}"
        if p == "postalCode":
            return f"{s}'s postal code is {o}" if first else f"postal code is {o}"
        if p == "ceremonialCounty":
            return f"{s} is in the ceremonial county of {o}" if first else f"ceremonial county is {o}"
        if p == "countySeat":
            return f"The county seat of {s} is {o}" if first else f"county seat is {o}"
        if p == "foundedBy":
            return f"{s} was founded by {o}" if first else f"founded by {o}"
        if p == "foundingYear":
            return f"{s} was founded in {o}" if first else f"founded in {o}"
        if p == "chief":
            return f"The chief of {s} is {o}" if first else f"chief is {o}"
        if p == "headquarter":
            return f"{s} has its headquarter at {o}" if first else f"headquarter is {o}"
        if p == "regionServed":
            return f"{s} serves the {o} region" if first else f"serves the {o} region"
        if p == "hubAirport":
            return f"{s} is a hub airport for {o}" if first else f"hub airport is {o}"
        if p == "class":
            return f"{s} belongs to the {o} class" if first else f"class is {o}"
        if p == "division":
            return f"{s} is in the {o} division" if first else f"division is {o}"
        if p == "order":
            return f"{s} is in the {o} order" if first else f"order is {o}"
        if p == "jurisdiction":
            return f"{s} has jurisdiction over {o}" if first else f"jurisdiction is {o}"
        if p == "city":
            return f"{s} is located in {o}" if first else f"city is {o}"
        # Fallback for any other predicate
        return f"{s} has {p} {o}" if first else f"has {p} {o}"

    # Build clauses
    clauses: list[str] = [_clause(t.subject, t.predicate, _clean(t.object)) for t in triples]

    # Combine clauses into a single complex sentence
    if len(clauses) == 1:
        sentence = clauses[0] + "."
    else:
        sentence = ", ".join(clauses[:-1]) + ", and " + clauses[-1] + "."

    # Capitalise first character
    return sentence[0].upper() + sentence[1:]

